from string_utils.generation import roman_range

def test_roman_range_overflow():
    # Test configuration that should raise an OverflowError
    try:
        # This should raise an OverflowError as starting from 5 to 1 with a step of -1 is valid,
        # and thus it should not raise an error in the original code.
        list(roman_range(1, start=5, step=-1))
        raise AssertionError("OverflowError was not raised")
    except OverflowError:
        pass  # This is expected
    except Exception as e:
        raise AssertionError(f"Unexpected exception: {str(e)}")
